function solve(nums, k) {
    const n = nums.length;
    const prefixMod = new Array(n + 1).fill(0);
    let modSum = 0;
    for (let i = 0; i < n; i++) {
        modSum = (modSum + nums[i]) % k;
        prefixMod[i + 1] = modSum;
    }

    const modIndices = new Map();
    modIndices.set(0, 0);
    let totalSum = 0;
    for (let num of nums) {
        totalSum += num;
    }

    let minSum = totalSum;
    for (let i = 1; i <= n; i++) {
        const currentMod = prefixMod[i];
        if (modIndices.has(currentMod)) {
            const j = modIndices.get(currentMod);
            const sum = prefixMod[i] - prefixMod[j];
            if (sum % k === 0) {
                const subarraySum = prefixMod[i] - prefixMod[j];
                minSum = Math.min(minSum, totalSum - subarraySum);
            }
        } else {
            modIndices.set(currentMod, i);
        }
    }
    return minSum;
}

