def solve(nums: list[int], k: int) -> int:
    n = len(nums)
    prefix_mod = [0] * (n + 1)
    mod_sum = 0
    for i in range(n):
        mod_sum = (mod_sum + nums[i]) % k
        prefix_mod[i + 1] = mod_sum

    mod_indices = {0: 0}
    total_sum = sum(nums)
    min_sum = total_sum

    for i in range(1, n + 1):
        current_mod = prefix_mod[i]
        if current_mod in mod_indices:
            j = mod_indices[current_mod]
            subarray_sum = sum(nums[j:i])
            if subarray_sum % k == 0:
                min_sum = min(min_sum, total_sum - subarray_sum)
        else:
            mod_indices[current_mod] = i

